/** 아이템 한국어 이름 → DDragon 이미지 URL. 못 찾으면 null. */
export function getItemImageUrl(name: string): string | null {
  // 정확한 매칭
  let id = ITEM_NAME_TO_ID[name];
  if (id) return `https://ddragon.leagueoflegends.com/cdn/${DDRAGON_VERSION}/img/item/${id}.png`;

  // 부분 매칭 (괄호 안 별명 등: "먹물 검 (이클립스)" → "이클립스" 검색)
  const parenMatch = name.match(/\((.+)\)/);
  if (parenMatch) {
    id = ITEM_NAME_TO_ID[parenMatch[1]];
    if (id) return `https://ddragon.leagueoflegends.com/cdn/${DDRAGON_VERSION}/img/item/${id}.png`;
  }

  // 이름에 포함된 키워드 매칭
  const entry = Object.entries(ITEM_NAME_TO_ID).find(([k]) => k.includes(name) || name.includes(k));
  if (entry) return `https://ddragon.leagueoflegends.com/cdn/${DDRAGON_VERSION}/img/item/${entry[1]}.png`;

  return null;
}
